import React, { useCallback } from 'react';
import { PeriodActionPanel } from '../../../components/kt/PeriodActionPanel';
import { ktService } from '../../../services/kt/ktService';
import { PERIOD_JOB_TYPES } from '../../../constants/periodJobTypes';
import { PERIOD_REFERENCE_NO } from '../../../constants/periodProcessReferences';
import { periodProcessStatusLabel } from '../../../utils/periodProcessStatusLabel';

const PhanBoKyPage: React.FC = () => {
  const getStatus = useCallback(
    async (m: number, y: number) => periodProcessStatusLabel(await ktService.getPeriodAllocationStatus(m, y)),
    [],
  );

  return (
    <PeriodActionPanel
      testIdPrefix="kt-phan-bo-cuoi-ky"
      title="Phân bổ cuối kỳ"
      icon="fa-share-alt"
      runLabel="Phân bổ"
      postLabel="Ghi sổ"
      jobType={PERIOD_JOB_TYPES.PeriodAllocation}
      referenceNo={PERIOD_REFERENCE_NO.Allocation}
      getStatus={getStatus}
      onRun={(m, y) => ktService.runPeriodAllocation(m, y)}
      onPost={(m, y) => ktService.postPeriodAllocation(m, y)}
    />
  );
};

export default PhanBoKyPage;
